//! Parse the committed tinystories fixture and pin its identity.
//!
//! The fixture is generated by `../rpi4-llm/fixtures/generate_fixture.py`;
//! regenerating it means re-pinning `FIXTURE_SHA256` here and in the demo.

use rpi4_llm_loader::parse;

const FIXTURE: &str = concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/../rpi4-llm/fixtures/tinystories-260k-f32.gguf"
);

pub const FIXTURE_SHA256: &str = "c0d530a15dc4a300be76df9622ee26f9103325f5ae58f4d486fbc2842ddf50ad";

fn sha256_hex(data: &[u8]) -> String {
    // Minimal SHA-256 (test-only): avoids a host-side crypto dependency.
    const K: [u32; 64] = [
        0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4,
        0xab1c5ed5, 0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe,
        0x9bdc06a7, 0xc19bf174, 0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f,
        0x4a7484aa, 0x5cb0a9dc, 0x76f988da, 0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7,
        0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967, 0x27b70a85, 0x2e1b2138, 0x4d2c6dfc,
        0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85, 0xa2bfe8a1, 0xa81a664b,
        0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070, 0x19a4c116,
        0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
        0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7,
        0xc67178f2,
    ];
    let mut h: [u32; 8] = [
        0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab,
        0x5be0cd19,
    ];
    let mut msg = data.to_vec();
    let bitlen = (data.len() as u64) * 8;
    msg.push(0x80);
    while msg.len() % 64 != 56 {
        msg.push(0);
    }
    msg.extend_from_slice(&bitlen.to_be_bytes());
    for chunk in msg.as_chunks::<64>().0 {
        let mut w = [0u32; 64];
        for (i, word) in chunk.as_chunks::<4>().0.iter().enumerate() {
            w[i] = u32::from_be_bytes(*word);
        }
        for i in 16..64 {
            let s0 = w[i - 15].rotate_right(7) ^ w[i - 15].rotate_right(18) ^ (w[i - 15] >> 3);
            let s1 = w[i - 2].rotate_right(17) ^ w[i - 2].rotate_right(19) ^ (w[i - 2] >> 10);
            w[i] = w[i - 16]
                .wrapping_add(s0)
                .wrapping_add(w[i - 7])
                .wrapping_add(s1);
        }
        let (mut a, mut b, mut c, mut d, mut e, mut f, mut g, mut hh) =
            (h[0], h[1], h[2], h[3], h[4], h[5], h[6], h[7]);
        for i in 0..64 {
            let s1 = e.rotate_right(6) ^ e.rotate_right(11) ^ e.rotate_right(25);
            let ch = (e & f) ^ (!e & g);
            let t1 = hh
                .wrapping_add(s1)
                .wrapping_add(ch)
                .wrapping_add(K[i])
                .wrapping_add(w[i]);
            let s0 = a.rotate_right(2) ^ a.rotate_right(13) ^ a.rotate_right(22);
            let maj = (a & b) ^ (a & c) ^ (b & c);
            let t2 = s0.wrapping_add(maj);
            hh = g;
            g = f;
            f = e;
            e = d.wrapping_add(t1);
            d = c;
            c = b;
            b = a;
            a = t1.wrapping_add(t2);
        }
        for (i, v) in [a, b, c, d, e, f, g, hh].into_iter().enumerate() {
            h[i] = h[i].wrapping_add(v);
        }
    }
    h.iter().map(|x| format!("{x:08x}")).collect()
}

#[test]
fn fixture_parses_and_matches_pin() {
    let buf = std::fs::read(FIXTURE).expect("committed fixture present");
    assert_eq!(sha256_hex(&buf), FIXTURE_SHA256, "fixture changed: re-pin");

    let d = parse(&buf).expect("fixture must parse");
    let c = d.config;
    assert_eq!(c.dim, 64);
    assert_eq!(c.hidden_dim, 176);
    assert_eq!(c.n_layers, 5);
    assert_eq!(c.n_heads, 8);
    assert_eq!(c.n_kv_heads, 4);
    assert_eq!(c.vocab_size, 259);
    assert_eq!(c.seq_len, 256);
    assert_eq!(c.head_size, 8);
    assert_eq!(c.bos_id, 1);
    assert_eq!(c.eos_id, 2);
    assert!(!d.tied_output);
    assert_eq!(d.tensors().len(), 48);

    // vocabulary walks cleanly: 3 specials + 256 byte pieces
    let toks: Vec<&[u8]> = d.tokens(&buf).collect();
    assert_eq!(toks.len(), 259);
    assert_eq!(toks[1], b"<s>");
    assert_eq!(toks[3], b"<0x00>");
    assert_eq!(toks[258], b"<0xFF>");

    // total parameter count matches the trainer's report
    let n_params: u64 = d
        .tensors()
        .iter()
        .map(|t| t.dims.iter().take(t.n_dims as usize).product::<u64>())
        .sum();
    // 264,256 = 247,680 trained parameters + the 259×64 token_embd
    // duplicated as output.weight (tied classifier written out).
    assert_eq!(n_params, 264_256);
}
